import React, { useState, useEffect, useCallback } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  CircularProgress,
  Alert,
  IconButton,
  useTheme,
  useMediaQuery,
  Fade,
  Skeleton,
  Tooltip,
  Stack,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  TextField,
  Switch,
  FormControlLabel
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  History,
  Assessment,
  Timeline,
  Schedule,
  FilterList
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';
import { applyTradeFilters, filterFullyRealizedTrades } from '../../utils/tradeFilters';

const FinishedOperationsModal = ({ open, onClose }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Estados principais
  const [trades, setTrades] = useState([]);
  const [filteredTrades, setFilteredTrades] = useState([]);
  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState('');
  const [lastUpdate, setLastUpdate] = useState(null);

  // Estados de filtros
  const [filters, setFilters] = useState({
    fullyRealized: false, // Mostrar todas as operações por padrão
    period: 'all',
    symbol: '',
    side: 'all',
    result: 'all'
  });
  const [showFilters, setShowFilters] = useState(false);

  // Estados de estatísticas
  const [stats, setStats] = useState({
    totalTrades: 0,
    totalPnL: 0,
    winRate: 0,
    totalVolume: 0
  });

  // Função para carregar trades com retry automático
  const loadTrades = useCallback(async (isRefresh = false) => {
    try {
      if (isRefresh) {
        setRefreshing(true);
      } else {
        setLoading(true);
        setTrades([]); // Limpar apenas no carregamento inicial
      }

      setError('');

      console.log('🔄 [FinishedOperationsModal] Carregando trades finalizados...', { isRefresh });

      const response = await dashboardService.getClosedTrades();
      console.log('📊 [FinishedOperationsModal] Resposta da API:', response);
      console.log('📊 [FinishedOperationsModal] Tipo da resposta:', typeof response);
      console.log('📊 [FinishedOperationsModal] Propriedades da resposta:', Object.keys(response || {}));

      // Processar resposta com validação robusta
      let tradesData = [];
      if (response?.trades && Array.isArray(response.trades)) {
        tradesData = response.trades;
        console.log('✅ [FinishedOperationsModal] Usando response.trades:', tradesData.length, 'trades');
      } else if (response?.data && Array.isArray(response.data)) {
        tradesData = response.data;
        console.log('✅ [FinishedOperationsModal] Usando response.data:', tradesData.length, 'trades');
      } else if (Array.isArray(response)) {
        tradesData = response;
        console.log('✅ [FinishedOperationsModal] Usando response diretamente:', tradesData.length, 'trades');
      } else {
        console.warn('⚠️ [FinishedOperationsModal] Formato de resposta não reconhecido:', response);
        tradesData = [];
      }

      console.log('📊 [FinishedOperationsModal] Trades encontrados:', tradesData.length);

      // Validar e limpar dados dos trades
      const validTrades = tradesData.filter(trade => {
        const isValid = trade && 
               trade.symbol && 
               trade.entry_price !== undefined && 
               trade.pnl !== undefined;
        if (!isValid) {
          console.warn('⚠️ [FinishedOperationsModal] Trade inválido filtrado:', trade);
        }
        return isValid;
      }).map((trade, index) => {
        // Debug: verificar se marginCoin está presente
        if (index === 0) {
          console.log('🔍 [FinishedOperationsModal] Primeiro trade - campos de margem:', {
            margin: trade.margin,
            marginCoin: trade.marginCoin,
            allFields: Object.keys(trade)
          });
        }

        return {
          ...trade,
          id: trade.id || `${trade.symbol}_${trade.closed_at || Date.now()}_${index}_${Math.random().toString(36).substr(2, 9)}`,
          pnl: parseFloat(trade.pnl) || 0,
          roe: parseFloat(trade.roe) || 0,
          margin: parseFloat(trade.margin) || 0,
          marginCoin: trade.marginCoin || 'USDT', // Garantir que marginCoin tenha um valor padrão
          size: parseFloat(trade.size) || 0,
          entry_price: parseFloat(trade.entry_price) || 0,
          exit_price: parseFloat(trade.exit_price) || 0
        };
      });

      console.log('✅ [FinishedOperationsModal] Trades processados:', validTrades.length);

      setTrades(validTrades);
      setLastUpdate(new Date());

    } catch (error) {
      console.error('❌ [FinishedOperationsModal] Erro ao carregar trades:', error);
      setError(`Erro ao carregar operações finalizadas: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  // Aplicar filtros aos trades
  const applyFilters = useCallback(() => {
    console.log('🔍 [FinishedOperationsModal] Aplicando filtros:', filters);
    console.log('📊 [FinishedOperationsModal] Total de trades antes dos filtros:', trades.length);

    let filtered = [...trades];

    // Aplicar filtros básicos usando a função utilitária
    filtered = applyTradeFilters(filtered, filters);

    // Aplicar filtro de operações totalmente realizadas se ativado
    if (filters.fullyRealized) {
      filtered = filterFullyRealizedTrades(filtered);
    }

    console.log('📊 [FinishedOperationsModal] Trades após filtros:', filtered.length);

    setFilteredTrades(filtered);

    // Calcular estatísticas dos trades filtrados
    const totalPnL = filtered.reduce((sum, trade) => sum + (parseFloat(trade.pnl) || 0), 0);
    const winningTrades = filtered.filter(trade => (parseFloat(trade.pnl) || 0) > 0).length;
    const winRate = filtered.length > 0 ? (winningTrades / filtered.length) * 100 : 0;
    const totalVolume = filtered.reduce((sum, trade) => sum + (parseFloat(trade.margin) || 0), 0);

    setStats({
      totalTrades: filtered.length,
      totalPnL,
      winRate,
      totalVolume
    });
  }, [trades, filters]);

  // Carregar trades quando o modal abrir
  useEffect(() => {
    if (open) {
      console.log('🚀 [FinishedOperationsModal] Modal aberto, carregando trades...');
      loadTrades();
    }
  }, [open, loadTrades]);

  // Aplicar filtros quando trades ou filtros mudarem
  useEffect(() => {
    applyFilters();
  }, [applyFilters]);

  // Função para formatar moeda
  const formatCurrency = (value, currency = 'USDT') => {
    const numValue = parseFloat(value) || 0;
    return `${numValue.toFixed(4)} ${currency}`;
  };

  // Função para formatar porcentagem
  const formatPercentage = (value) => {
    const numValue = parseFloat(value) || 0;
    return `${numValue.toFixed(2)}%`;
  };

  // Função para determinar cor do PnL
  const getPnLColor = (pnl) => {
    const numPnL = parseFloat(pnl) || 0;
    if (numPnL > 0) return 'success.main';
    if (numPnL < 0) return 'error.main';
    return 'text.secondary';
  };

  // Função para refresh manual
  const handleRefresh = () => {
    loadTrades(true);
  };

  // Função para resetar filtros
  const resetFilters = () => {
    setFilters({
      fullyRealized: false,
      period: 'all',
      symbol: '',
      side: 'all',
      result: 'all'
    });
  };

  return (
    <Dialog 
      open={open} 
      onClose={onClose} 
      maxWidth="xl" 
      fullWidth
      fullScreen={isMobile}
      PaperProps={{
        sx: {
          height: isMobile ? '100vh' : '90vh',
          bgcolor: 'background.paper'
        }
      }}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        bgcolor: 'primary.main',
        color: 'primary.contrastText',
        py: 2
      }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <History />
          <Typography variant="h6" component="div">
            Operações Finalizadas ({filteredTrades.length})
          </Typography>
        </Box>

        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Tooltip title="Atualizar">
            <IconButton 
              onClick={handleRefresh} 
              disabled={loading || refreshing}
              sx={{ color: 'inherit' }}
            >
              <Refresh sx={{ 
                animation: refreshing ? 'spin 1s linear infinite' : 'none',
                '@keyframes spin': {
                  '0%': { transform: 'rotate(0deg)' },
                  '100%': { transform: 'rotate(360deg)' }
                }
              }} />
            </IconButton>
          </Tooltip>

          <Tooltip title="Filtros">
            <IconButton 
              onClick={() => setShowFilters(!showFilters)}
              sx={{ 
                color: 'inherit',
                bgcolor: showFilters ? 'rgba(255,255,255,0.1)' : 'transparent'
              }}
            >
              <FilterList />
            </IconButton>
          </Tooltip>

          <IconButton onClick={onClose} sx={{ color: 'inherit' }}>
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ p: 0, display: 'flex', flexDirection: 'column', height: '100%' }}>
        {/* Painel de Filtros */}
        <Fade in={showFilters}>
          <Box sx={{ 
            p: 2, 
            bgcolor: 'background.default',
            borderBottom: 1,
            borderColor: 'divider',
            display: showFilters ? 'block' : 'none'
          }}>
            <Stack direction={isMobile ? 'column' : 'row'} spacing={2} alignItems="center">
              <FormControl size="small" sx={{ minWidth: 120 }}>
                <InputLabel>Período</InputLabel>
                <Select
                  value={filters.period}
                  label="Período"
                  onChange={(e) => setFilters(prev => ({ ...prev, period: e.target.value }))}
                >
                  <MenuItem value="all">Todos</MenuItem>
                  <MenuItem value="today">Hoje</MenuItem>
                  <MenuItem value="week">Esta Semana</MenuItem>
                  <MenuItem value="month">Este Mês</MenuItem>
                </Select>
              </FormControl>

              <TextField
                size="small"
                label="Símbolo"
                value={filters.symbol}
                onChange={(e) => setFilters(prev => ({ ...prev, symbol: e.target.value }))}
                sx={{ minWidth: 120 }}
              />

              <FormControl size="small" sx={{ minWidth: 120 }}>
                <InputLabel>Lado</InputLabel>
                <Select
                  value={filters.side}
                  label="Lado"
                  onChange={(e) => setFilters(prev => ({ ...prev, side: e.target.value }))}
                >
                  <MenuItem value="all">Todos</MenuItem>
                  <MenuItem value="long">Long</MenuItem>
                  <MenuItem value="short">Short</MenuItem>
                </Select>
              </FormControl>

              <FormControl size="small" sx={{ minWidth: 120 }}>
                <InputLabel>Resultado</InputLabel>
                <Select
                  value={filters.result}
                  label="Resultado"
                  onChange={(e) => setFilters(prev => ({ ...prev, result: e.target.value }))}
                >
                  <MenuItem value="all">Todos</MenuItem>
                  <MenuItem value="profit">Lucro</MenuItem>
                  <MenuItem value="loss">Prejuízo</MenuItem>
                </Select>
              </FormControl>

              <FormControlLabel
                control={
                  <Switch
                    checked={filters.fullyRealized}
                    onChange={(e) => setFilters(prev => ({ ...prev, fullyRealized: e.target.checked }))}
                    size="small"
                  />
                }
                label="Apenas Totalmente Realizadas"
              />

              <Button 
                variant="outlined" 
                size="small" 
                onClick={resetFilters}
              >
                Limpar
              </Button>
            </Stack>
          </Box>
        </Fade>

        {/* Estatísticas */}
        <Box sx={{ 
          p: 2, 
          bgcolor: 'background.default',
          borderBottom: 1,
          borderColor: 'divider'
        }}>
          <Stack direction={isMobile ? 'column' : 'row'} spacing={3}>
            <Box sx={{ textAlign: 'center' }}>
              <Typography variant="h6" color="primary">
                {stats.totalTrades}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Total de Operações
              </Typography>
            </Box>

            <Box sx={{ textAlign: 'center' }}>
              <Typography 
                variant="h6" 
                sx={{ color: getPnLColor(stats.totalPnL) }}
              >
                {formatCurrency(stats.totalPnL)}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                PnL Total
              </Typography>
            </Box>

            <Box sx={{ textAlign: 'center' }}>
              <Typography 
                variant="h6" 
                sx={{ color: stats.winRate >= 50 ? 'success.main' : 'error.main' }}
              >
                {formatPercentage(stats.winRate)}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Taxa de Acerto
              </Typography>
            </Box>

            <Box sx={{ textAlign: 'center' }}>
              <Typography variant="h6" color="info.main">
                {formatCurrency(stats.totalVolume)}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Volume Total
              </Typography>
            </Box>
          </Stack>
        </Box>

        {/* Conteúdo Principal */}
        <Box sx={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
          {error && (
            <Alert severity="error" sx={{ m: 2 }}>
              {error}
            </Alert>
          )}

          {loading ? (
            <Box sx={{ p: 2 }}>
              {[...Array(5)].map((_, index) => (
                <Skeleton key={index} variant="rectangular" height={60} sx={{ mb: 1 }} />
              ))}
            </Box>
          ) : filteredTrades.length === 0 ? (
            <Box sx={{ 
              flex: 1, 
              display: 'flex', 
              flexDirection: 'column', 
              alignItems: 'center', 
              justifyContent: 'center',
              p: 4
            }}>
              <Schedule sx={{ fontSize: 64, color: 'text.secondary', mb: 2 }} />
              <Typography variant="h6" color="text.secondary" gutterBottom>
                Nenhuma operação finalizada
              </Typography>
              <Typography variant="body2" color="text.secondary" textAlign="center">
                As operações finalizadas aparecerão aqui automaticamente.
                <br />
                Certifique-se de que suas credenciais da API estão configuradas corretamente.
              </Typography>
              <Button 
                variant="outlined" 
                startIcon={<Refresh />}
                onClick={handleRefresh}
                sx={{ mt: 2 }}
              >
                Tentar Novamente
              </Button>
            </Box>
          ) : (
            <TableContainer component={Paper} sx={{ flex: 1, overflow: 'auto' }}>
              <Table stickyHeader>
                <TableHead>
                  <TableRow>
                    <TableCell>Símbolo</TableCell>
                    <TableCell>Lado</TableCell>
                    <TableCell align="right">Tamanho</TableCell>
                    <TableCell align="right">Preço Entrada</TableCell>
                    <TableCell align="right">Preço Saída</TableCell>
                    <TableCell align="right">PnL</TableCell>
                    <TableCell align="right">ROE</TableCell>
                    <TableCell align="right">Margem</TableCell>
                    <TableCell>Data Fechamento</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {filteredTrades.map((trade) => (
                    <TableRow key={trade.id} hover>
                      <TableCell>
                        <Typography variant="body2" fontWeight="medium">
                          {trade.symbol}
                        </Typography>
                      </TableCell>

                      <TableCell>
                        <Chip
                          label={trade.side?.toUpperCase() || 'N/A'}
                          size="small"
                          color={trade.side === 'long' ? 'success' : 'error'}
                          variant="outlined"
                        />
                      </TableCell>

                      <TableCell align="right">
                        <Typography variant="body2">
                          {parseFloat(trade.size || 0).toFixed(4)}
                        </Typography>
                      </TableCell>

                      <TableCell align="right">
                        <Typography variant="body2">
                          ${parseFloat(trade.entry_price || 0).toFixed(4)}
                        </Typography>
                      </TableCell>

                      <TableCell align="right">
                        <Typography variant="body2">
                          ${parseFloat(trade.exit_price || 0).toFixed(4)}
                        </Typography>
                      </TableCell>

                      <TableCell align="right">
                        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: 0.5 }}>
                          {parseFloat(trade.pnl || 0) > 0 ? (
                            <TrendingUp sx={{ fontSize: 16, color: 'success.main' }} />
                          ) : parseFloat(trade.pnl || 0) < 0 ? (
                            <TrendingDown sx={{ fontSize: 16, color: 'error.main' }} />
                          ) : null}
                          <Typography 
                            variant="body2" 
                            sx={{ color: getPnLColor(trade.pnl), fontWeight: 'medium' }}
                          >
                            {formatCurrency(trade.pnl, trade.marginCoin)}
                          </Typography>
                        </Box>
                      </TableCell>

                      <TableCell align="right">
                        <Typography 
                          variant="body2" 
                          sx={{ color: getPnLColor(trade.roe) }}
                        >
                          {formatPercentage(trade.roe)}
                        </Typography>
                      </TableCell>

                      <TableCell align="right">
                        <Typography variant="body2">
                          {formatCurrency(trade.margin, trade.marginCoin)}
                        </Typography>
                      </TableCell>

                      <TableCell>
                        <Typography variant="body2" color="text.secondary">
                          {trade.closed_at ? new Date(trade.closed_at).toLocaleString() : 'N/A'}
                        </Typography>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          )}
        </Box>
      </DialogContent>

      <DialogActions sx={{
        bgcolor: 'background.default',
        justifyContent: 'space-between',
        px: 3,
        py: 2
      }}>
        <Typography variant="caption" color="text.secondary">
          {lastUpdate && (
            <>Última atualização: {lastUpdate.toLocaleTimeString()}</>  
          )}
          {refreshing && ' • Atualizando...'}
        </Typography>

        <Button 
          onClick={onClose} 
          variant="contained" 
          size="large"
          startIcon={<Close />}
        >
          Fechar
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default FinishedOperationsModal;
